import React, { useState, useEffect, createContext, useContext, useCallback } from 'react';
import { Routes, Route, Link, useNavigate, Navigate } from 'react-router-dom';
import axios from 'axios';
import Home from './pages/Home';
import Login from './pages/Login';
import Register from './components/Register';
import HospitalDetail from './pages/HospitalDetail';

/* ── Axios defaults ───────────────────────────────────────────── */
axios.defaults.baseURL = 'http://localhost:5000';
axios.defaults.withCredentials = true;

/* ── Auth Context ─────────────────────────────────────────────── */
const AuthContext = createContext(null);
export const useAuth = () => useContext(AuthContext);

function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [unreadCount, setUnreadCount] = useState(0);

  const fetchUser = useCallback(async () => {
    try {
      const res = await axios.get('/api/me');
      setUser(res.data);
    } catch {
      setUser(null);
    } finally {
      setLoading(false);
    }
  }, []);

  const fetchUnread = useCallback(async () => {
    try {
      const res = await axios.get('/api/notifications');
      setUnreadCount(res.data.filter(n => !n.is_read).length);
    } catch {
      setUnreadCount(0);
    }
  }, []);

  useEffect(() => { fetchUser(); }, [fetchUser]);
  // Poll for notifications every 30 seconds when logged in
  useEffect(() => {
    if (!user) return;
    fetchUnread();
    const interval = setInterval(fetchUnread, 30000);
    return () => clearInterval(interval);
  }, [user, fetchUnread]);

  const login = async (email, password) => {
    const res = await axios.post('/api/login', { email, password });
    setUser(res.data.user);
    return res.data;
  };

  const register = async (data) => {
    const res = await axios.post('/api/register', data);
    return res.data;
  };

  const logout = async () => {
    await axios.post('/api/logout');
    setUser(null);
    setUnreadCount(0);
  };

  return (
    <AuthContext.Provider value={{ user, loading, login, register, logout, fetchUser, unreadCount, setUnreadCount }}>
      {children}
    </AuthContext.Provider>
  );
}

/* ── Protected Route ──────────────────────────────────────────── */
function ProtectedRoute({ children }) {
  const { user, loading } = useAuth();
  if (loading) return <div style={{textAlign:'center',padding:'4rem'}}>Loading...</div>;
  if (!user) return <Navigate to="/login" />;
  return children;
}

/* ── Navbar ───────────────────────────────────────────────────── */
function Navbar() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = async () => {
    await logout();
    navigate('/');
  };

  return (
    <nav style={styles.nav}>
      <Link to="/" style={styles.brand}>🏥 Arogya</Link>
      <div style={styles.navLinks}>
        <Link to="/" style={styles.navLink}>Home</Link>
        {user ? (
          <>
            <Link to="/appointments" style={styles.navLink}>My Appointments</Link>
            <Link to="/notifications" style={styles.navLink}>Notifications</Link>
            <button onClick={handleLogout} style={styles.navBtn}>Logout</button>
          </>
        ) : (
          <>
            <Link to="/login" style={styles.navLink}>Login</Link>
            <Link to="/register" style={styles.navLinkHighlight}>Sign Up</Link>
          </>
        )}
      </div>
    </nav>
  );
}

/* ── Appointments Page ────────────────────────────────────────── */
function AppointmentsPage() {
  const [appointments, setAppointments] = useState([]);
  const [message, setMessage] = useState('');
  const [reschedule, setReschedule] = useState(null);
  const [newDate, setNewDate] = useState('');
  const [newTime, setNewTime] = useState('');

  const fetchAppts = useCallback(async () => {
    try {
      const r = await axios.get('/api/appointments');
      setAppointments(r.data);
    } catch {}
  }, []);

  useEffect(() => { fetchAppts(); }, [fetchAppts]);

  const cancelAppt = async (id) => {
    if (!window.confirm('Are you sure you want to cancel this appointment?')) return;
    try {
      await axios.put(`/api/appointments/${id}/cancel`);
      setMessage('Appointment cancelled');
      fetchAppts();
    } catch (e) { setMessage(e.response?.data?.error || 'Cancel failed'); }
  };

  const doReschedule = async (id) => {
    try {
      await axios.put(`/api/appointments/${id}/reschedule`, { date: newDate, time_slot: newTime });
      setMessage('Appointment rescheduled');
      setReschedule(null);
      fetchAppts();
    } catch (e) { setMessage(e.response?.data?.error || 'Reschedule failed'); }
  };

  return (
    <div style={styles.container}>
      <h1 style={styles.pageTitle}>My Appointments</h1>
      {message && <div style={styles.alert}>{message}</div>}

      {appointments.length === 0 ? (
        <div style={styles.emptyPanel}>
          <h3>No Appointments</h3>
          <p>Go to the dashboard to book your first appointment.</p>
        </div>
      ) : (
        <div style={styles.apptList}>
          {appointments.map(a => (
            <div key={a.id} style={styles.apptCard}>
              <div style={styles.apptHeader}>
                <h3 style={{margin:0}}>Dr. {a.doctor_name}</h3>
                <span style={{...styles.badge, ...(a.status === 'confirmed' ? styles.badgeConfirmed : a.status === 'cancelled' ? styles.badgeCancelled : styles.badgeCompleted)}}>
                  {a.status}
                </span>
              </div>
              <p style={{color:'#6c757d', margin:'0.25rem 0'}}>{a.hospital_name ? `🏥 ${a.hospital_name} • ` : ''}{a.specialization} • {a.department}</p>
              <p style={{margin:'0.25rem 0'}}><strong>📅 {a.date}</strong> at <strong>{a.time_slot}</strong></p>
              {a.notes && <p style={{color:'#6c757d', fontSize:'0.85rem'}}>Notes: {a.notes}</p>}

              {a.status === 'confirmed' && (
                <div style={{display:'flex', gap:'0.5rem', marginTop:'0.75rem'}}>
                  <button onClick={() => cancelAppt(a.id)} style={styles.btnDanger}>Cancel</button>
                  <button onClick={() => { setReschedule(a.id); setNewDate(a.date); setNewTime(a.time_slot); }}
                    style={styles.btnOutline}>Reschedule</button>
                </div>
              )}

              {reschedule === a.id && (
                <div style={{marginTop:'1rem', padding:'1rem', background:'#f8f9fa', borderRadius:'8px'}}>
                  <label style={styles.label}>New Date</label>
                  <input type="date" value={newDate} onChange={e => setNewDate(e.target.value)} style={styles.input} min={new Date().toISOString().split('T')[0]} />
                  <label style={{...styles.label, marginTop:'0.5rem'}}>New Time Slot</label>
                  <input type="time" value={newTime} onChange={e => setNewTime(e.target.value)} style={styles.input} />
                  <div style={{display:'flex', gap:'0.5rem', marginTop:'0.75rem'}}>
                    <button onClick={() => doReschedule(a.id)} style={styles.btnPrimary}>Confirm</button>
                    <button onClick={() => setReschedule(null)} style={styles.btnOutline}>Cancel</button>
                  </div>
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

/* ── Notifications Page ───────────────────────────────────────── */
function NotificationsPage() {
  const { setUnreadCount } = useAuth();
  const [notifs, setNotifs] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    axios.get('/api/notifications')
      .then(r => { setNotifs(r.data); })
      .catch(() => {})
      .finally(() => setLoading(false));
    // Mark all as read
    axios.put('/api/notifications/read')
      .then(() => setUnreadCount(0))
      .catch(() => {});
  }, [setUnreadCount]);

  const typeIcons = { booking: '📅', cancellation: '❌', reschedule: '🔄', system: 'ℹ️', info: 'ℹ️' };
  const typeColors = { booking: '#E6F0FF', cancellation: '#FFF0F0', reschedule: '#FFF8E6', system: '#F0F8F0', info: '#F0F8F0' };
  const typeBorder = { booking: '#2D68FE', cancellation: '#dc3545', reschedule: '#f57c00', system: '#2E7D32', info: '#2E7D32' };

  return (
    <div style={{background:'#f8f9fa', minHeight:'100vh', padding:'2rem 0'}}>
      <div style={{maxWidth:'800px', margin:'0 auto', padding:'0 1.5rem'}}>
        <h1 style={{fontSize:'1.75rem', fontWeight:800, marginBottom:'1.5rem', color:'#1A1D27'}}>🔔 Notifications</h1>
        {loading ? (
          <p style={{textAlign:'center', color:'#6c757d', padding:'3rem'}}>Loading...</p>
        ) : notifs.length === 0 ? (
          <div style={{background:'#fff', borderRadius:'16px', padding:'4rem', textAlign:'center', color:'#6c757d', boxShadow:'0 2px 12px rgba(0,0,0,0.05)'}}>
            <div style={{fontSize:'3rem', marginBottom:'1rem'}}>🔕</div>
            <h3 style={{margin:0}}>No notifications yet</h3>
            <p>You're all caught up! Notifications will appear here after booking appointments.</p>
          </div>
        ) : (
          <div style={{display:'flex', flexDirection:'column', gap:'0.75rem'}}>
            {notifs.map(n => (
              <div key={n.id} style={{
                background: n.is_read ? '#fff' : typeColors[n.type] || '#F0F4FF',
                borderRadius:'12px',
                padding:'1.25rem 1.5rem',
                boxShadow:'0 2px 8px rgba(0,0,0,0.05)',
                borderLeft:`4px solid ${typeBorder[n.type] || '#2D68FE'}`,
                opacity: n.is_read ? 0.75 : 1,
                transition:'all 0.2s'
              }}>
                <p style={{margin:0, fontSize:'1rem', color:'#1A1D27', fontWeight: n.is_read ? 400 : 600}}>
                  {typeIcons[n.type] || 'ℹ️'} {n.message}
                </p>
                <p style={{margin:'0.4rem 0 0', color:'#adb5bd', fontSize:'0.8rem'}}>
                  {new Date(n.created_at).toLocaleString('en-IN')}
                  {!n.is_read && <span style={{marginLeft:'0.5rem', color:'#2D68FE', fontWeight:600, fontSize:'0.75rem'}}>● NEW</span>}
                </p>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

/* ── App Root ─────────────────────────────────────────────────── */
export default function App() {
  return (
    <AuthProvider>
      <div style={{minHeight:'100vh', background:'#f0f2f5', fontFamily:"'Inter', system-ui, sans-serif"}}>
        <Navbar />
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/hospital/:id" element={<HospitalDetail />} />
          <Route path="/login" element={<Login />} />
          <Route path="/register" element={<Register />} />
          <Route path="/appointments" element={<ProtectedRoute><AppointmentsPage /></ProtectedRoute>} />
          <Route path="/notifications" element={<ProtectedRoute><NotificationsPage /></ProtectedRoute>} />
        </Routes>
      </div>
    </AuthProvider>
  );
}

